// Mapeo columnas Google Sheets → schema agencia_leads
// Ajustar los nombres de columna según el sheet real de Robert
const row = $input.first().json;

// Intentar leer nombre completo o separado
const nombreCompleto = row['Nombre'] || row['nombre'] || row['Nombre completo'] || '';
const partes = nombreCompleto.trim().split(' ');
const nombre = partes[0] || '';
const apellido = partes.slice(1).join(' ') || row['Apellido'] || row['apellido'] || '';

// Teléfono / WhatsApp
const whatsapp = String(row['Teléfono'] || row['Telefono'] || row['telefono'] || row['WhatsApp'] || row['whatsapp'] || '').replace(/\s+/g, '');

// Email
const email = row['Email'] || row['Correo'] || row['correo'] || row['email'] || null;

// Empresa / Agencia
const empresa = row['Empresa'] || row['empresa'] || row['Agencia'] || row['Compañía'] || null;

// Mensaje / Notas
const notas = row['Mensaje'] || row['mensaje'] || row['Comentarios'] || row['comentarios'] || row['Consulta'] || null;

// Servicio / Interés
const servicio = row['Servicio'] || row['servicio'] || row['Interés'] || row['interes'] || null;
const notasCompletas = [servicio ? `Servicio: ${servicio}` : null, notas].filter(Boolean).join(' | ');

return [{
  json: {
    nombre_contacto: nombre,
    apellido_contacto: apellido,
    nombre_empresa: empresa,
    whatsapp: whatsapp,
    email: email,
    fuente_id: 1,
    canal_raw: 'formulario_web',
    estado: 'lead',
    notas: notasCompletas || null
  }
}];
